  ('islands-e3452428-moex-00030', 'islands-e3452428', 'islands-e3452428-moex-114-9f7bb576', 'sub-islands-e3452428-01', NULL, 'single_choice', '16歲之未成年人甲騎摩托車，不慎撞倒闖紅燈之學童乙，致乙受到重傷。下列敘述何者錯誤？', '["甲行為時有識別能力，與其法定代理人負連帶損害賠償責任", "甲行為時無識別能力，由法定代理人單獨負損害賠償責任", "甲得主張乙與有過失，減輕賠償金額或免除之", "甲僅於故意時才負損害賠償責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "f013c80b1205", "answer_pdf_sha1": "1a2ba8763e84", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗（作文、英文閱讀與法學知識）", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00031', 'islands-e3452428', 'islands-e3452428-moex-114-4dccc0e6', 'sub-islands-e3452428-02', NULL, 'single_choice', '關於政府與企業在管理上之異同比較，下列何者錯誤？ 政府與企業均以人、財、事、物為管理對象 政府與企業均重視服務對象的滿意度 政府追求社會整體公共利益的提升，而企業則以私人利潤的最大化為主要目的 政府跟企業都不能獨占對於特定事業的提供', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "06786d62fb55", "answer_pdf_sha1": "242e83f0aff7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0512", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00032', 'islands-e3452428', 'islands-e3452428-moex-114-4dccc0e6', 'sub-islands-e3452428-02', NULL, 'single_choice', '公務人員學習行政學的目的，下列何者錯誤？ 提高行政的效率及效果   促進社會階層的流動 促進社會的公平正義    促進科學的、系統的、制度化的行政現代化', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "06786d62fb55", "answer_pdf_sha1": "242e83f0aff7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0512", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00033', 'islands-e3452428', 'islands-e3452428-moex-114-4dccc0e6', 'sub-islands-e3452428-02', NULL, 'single_choice', '下列何者不是行政學傳統理論時期（1930之前）的主要論點？ 主張政治與行政要加以區分  強調運用科學方法建立標準工作流程 採用官僚體制作為政府組織的運作基礎  強調組織與外在環境處於開放系統的概念', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "06786d62fb55", "answer_pdf_sha1": "242e83f0aff7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0512", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00034', 'islands-e3452428', 'islands-e3452428-moex-114-4dccc0e6', 'sub-islands-e3452428-02', NULL, 'single_choice', '將行為科學與行政的研究相互結合是修正理論時期（1930～1960）的行政學特色，關於此一時期的研究特 色，下列何者正確？ 強調從制度面進行規範性研究  摒除自然科學研究方法的使用 企圖對社會現象提出通則性解釋  探究個人在獨立作業下的行為模式', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "06786d62fb55", "answer_pdf_sha1": "242e83f0aff7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0512", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00035', 'islands-e3452428', 'islands-e3452428-moex-114-4dccc0e6', 'sub-islands-e3452428-02', NULL, 'single_choice', '強調行政人員應跳脫單一執行者的角色，轉而培養倫理自主性，以公平正義的行政作為積極為民服務，受 到下列那一個理論的啟發？ 新公共服務理論  新公共管理理論  新公共行政理論  激勵保健理論', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "06786d62fb55", "answer_pdf_sha1": "242e83f0aff7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0512", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00036', 'islands-e3452428', 'islands-e3452428-moex-114-4dccc0e6', 'sub-islands-e3452428-02', NULL, 'single_choice', '下列何者不是新公共管理學派所提倡的政府行政策略？ 契約外包  公私合夥  行政管制  稅制誘因', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "06786d62fb55", "answer_pdf_sha1": "242e83f0aff7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0512", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00037', 'islands-e3452428', 'islands-e3452428-moex-114-4dccc0e6', 'sub-islands-e3452428-02', NULL, 'single_choice', '民營化類型可概分為撤資、委託、替代，下列何者不是「替代」的民營化類型？ 政策鼓勵民間設立電廠   公營銀行規模縮減或出售民間 私人保全公司負責安全保護  政府公開招標道路養護工程', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "06786d62fb55", "answer_pdf_sha1": "242e83f0aff7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0512", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
